// Function to apply softmax (Optional, if your model doesn't include it)
void Softmax(float* input, float* output, size_t count) {
    float max_val = input[0];
    for (size_t i = 1; i < count; i++) {
        if (input[i] > max_val) max_val = input[i];
    }

    float sum_exp = 0.0f;
    for (size_t i = 0; i < count; i++) {
        output[i] = expf(input[i] - max_val); // Subtraction for numerical stability
        sum_exp += output[i];
    }

    for (size_t i = 0; i < count; i++) {
        output[i] /= sum_exp;
    }
}

// Function to get the index of the max element
