#include <stb_image.h>
#include <onnxruntime_c_api.h>
#include <stdio.h>

// Define the target input size
#define TARGET_HEIGHT 224
#define TARGET_WIDTH  224
#define TARGET_CHANNELS 3

// Helper function to preprocess the image and create a tensor
void LoadImageAsTensor(const char* image_path, OrtAllocator* allocator, OrtValue** input_tensor) {
    // Load image using stb_image
    int width, height, channels;
    unsigned char* img_data = stbi_load(image_path, &width, &height, &channels, TARGET_CHANNELS);

    if (!img_data) {
        fprintf(stderr, "Failed to load image: %s\n", image_path);
        return;
    }

    // Resize and preprocess the image to meet the model input requirements
    float* input_data = (float*)malloc(TARGET_HEIGHT * TARGET_WIDTH * TARGET_CHANNELS * sizeof(float));

    for (int y = 0; y < TARGET_HEIGHT; ++y) {
        for (int x = 0; x < TARGET_WIDTH; ++x) {
            for (int c = 0; c < TARGET_CHANNELS; ++c) {
                int src_x = x * width / TARGET_WIDTH;
                int src_y = y * height / TARGET_HEIGHT;
                int src_index = (src_y * width + src_x) * TARGET_CHANNELS + c;
                int dst_index = (y * TARGET_WIDTH + x) * TARGET_CHANNELS + c;
                input_data[dst_index] = img_data[src_index] / 255.0f; // Normalize to 0.0 - 1.0
            }
        }
    }

    stbi_image_free(img_data);

    // Define tensor dimensions
    int64_t input_dims[4] = {1, TARGET_CHANNELS, TARGET_HEIGHT, TARGET_WIDTH};

    // Create tensor
    OrtApi* g_ort = OrtGetApiBase()->GetApi(ORT_API_VERSION);
    g_ort->CreateTensorWithDataAsOrtValue(allocator, input_data, TARGET_HEIGHT * TARGET_WIDTH * TARGET_CHANNELS * sizeof(float), input_dims, 4, ONNX_TENSOR_ELEMENT_DATA_TYPE_FLOAT, input_tensor);

    // Free the input data after tensor creation
    free(input_data);

    // You may want to add error checking here to ensure the tensor is created correctly
}
